const addMinutesToTime = (time, mins)=>{
    try {
        let h, m;
        const normalizedTime = (time || '').toUpperCase();
        if (!time || normalizedTime === 'ASAP') {
            const now = new Date();
            h = now.getHours();
            m = now.getMinutes();
        } else {
            const parts = time.split(':');
            [h, m] = parts.length === 2 ? parts.map(Number) : [
                new Date().getHours(),
                new Date().getMinutes()
            ];
        }
        const date = new Date();
        date.setHours(h, m + mins);
        return `${date.getHours().toString().padStart(2, '0')}:${date.getMinutes().toString().padStart(2, '0')}`;
    } catch  {
        return time;
    }
};
